{revenue.toFixed(0)} is below the minimum threshold of 

![equation](https://latex.codecogs.com/png.latex?\bg_white&space;%7BCONFIG.THRESHOLDS.MIN_REVENUE%7D.%60%0A%20%20%20%20%7D%29%3B%0A%20%20%7D%0A%7D%0A%60%60%60%0A%0A%23%23%20Weekly%20Executive%20Summary%0A%0AThe%20weekly%20summary%20aggregates%20the%20last%20seven%20rows%20of%20the%20archive%20tab%20and%20emails%20a%20formatted%20digest%20to%20the%20executive%20distribution%20list.%20Apps%20Script%27s%20%60MailApp.sendEmail%28%29%60%20supports%20HTML%20bodies%2C%20so%20the%20summary%20can%20include%20basic%20formatting%20%E2%80%94%20bold%20headers%2C%20colored%20variance%20indicators%20%E2%80%94%20without%20requiring%20any%20external%20email%20service.%0A%0A%60%60%60javascript%0Afunction%20sendWeeklyExecutiveSummary%28%29%20%7B%0A%20%20const%20archive%20%20%3D%20SpreadsheetApp.getActiveSpreadsheet%28%29%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20.getSheetByName%28CONFIG.ARCHIVE_TAB%29%3B%0A%20%20const%20lastRow%20%20%3D%20archive.getLastRow%28%29%3B%0A%20%20const%20weekData%20%3D%20archive.getRange%28lastRow%20-%206%2C%201%2C%207%2C%203%29.getValues%28%29%3B%0A%0A%20%20const%20totalRevenue%20%3D%20weekData.reduce%28%28sum%2C%20row%29%20%3D%3E%20sum%20%2B%20row%5B1%5D%2C%200%29%3B%0A%20%20const%20avgVariance%20%20%3D%20weekData.reduce%28%28sum%2C%20row%29%20%3D%3E%20sum%20%2B%20row%5B2%5D%2C%200%29%20%2F%20weekData.length%3B%0A%0A%20%20const%20body%20%3D%20%60%3Ch2%3EWeekly%20Performance%20Summary%3C%2Fh2%3E%0A%20%20%20%20%3Cp%3E%3Cstrong%3ETotal%20Revenue%20%287-day%29%3A%3C%2Fstrong%3E)

{totalRevenue.toFixed(0)}</p>
    <p><strong>Average Variance:</strong> ${(avgVariance * 100).toFixed(1)}%</p>`;

  MailApp.sendEmail({
    to:      CONFIG.EXEC_EMAILS.join(','),
    subject: `Weekly Summary — Week of ${weekData[0][0].toLocaleDateString()}`,
    htmlBody: body
  });
